using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Shared state for the note-taking tool ──────────────────────────────────
var notebook = new List<string>();

// ── Tool definitions ───────────────────────────────────────────────────────

[Description("Search the web for information. Returns result snippets from DuckDuckGo.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    var url = $"https://api.duckduckgo.com/?q={WebUtility.UrlEncode(query)}&format=json&no_redirect=1&no_html=1";
    var json = await http.GetStringAsync(url);
    var doc = JsonDocument.Parse(json);
    var root = doc.RootElement;

    var sb = new StringBuilder();

    var abs = root.GetProperty("Abstract").GetString();
    if (!string.IsNullOrWhiteSpace(abs))
    {
        var src = root.GetProperty("AbstractSource").GetString();
        sb.AppendLine($"[{src}] {abs}");
    }

    if (root.TryGetProperty("RelatedTopics", out var topics))
    {
        foreach (var topic in topics.EnumerateArray().Take(8))
        {
            if (topic.TryGetProperty("Text", out var text))
                sb.AppendLine($"• {text.GetString()}");
        }
    }

    return sb.Length > 0
        ? sb.ToString()
        : "No results found for that query. Try rephrasing or using different keywords.";
}

[Description("Save a research note. Use this to record important facts or findings.")]
Task<string> TakeNote(
    [Description("The content of the note")] string content)
{
    notebook.Add(content);
    return Task.FromResult($"Note #{notebook.Count} saved.");
}

[Description("Retrieve all research notes collected so far.")]
Task<string> GetNotes()
{
    if (notebook.Count == 0)
        return Task.FromResult("No notes saved yet.");

    var sb = new StringBuilder();
    for (var i = 0; i < notebook.Count; i++)
        sb.AppendLine($"[{i + 1}] {notebook[i]}");
    return Task.FromResult(sb.ToString());
}

// ── Build the AI client with automatic tool invocation ─────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Please set the OPENAI_API_KEY environment variable.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(GetNotes),
};

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── Get the research topic ─────────────────────────────────────────────────

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser("What topic would you like to research?");

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent loop ─────────────────────────────────────────────────────

var systemPrompt = """
    You are a research agent. Your goal is to thoroughly research the given topic
    using the tools available to you.

    Follow this process:
    1. Search the web for information about the topic using several varied queries.
    2. As you find useful information, save key facts using the note-taking tool.
    3. After gathering enough information (at least 3-4 searches), retrieve your notes
       and synthesize them into a well-structured summary.

    Always finish by presenting a clear, organized summary of your findings to the user.
    Use markdown formatting for the summary (headings, bullet points, etc.).
    """;

var history = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

await foreach (var update in client.GetStreamingResponseAsync(history, options))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// ── Helpers ─────────────────────────────────────────────────────────────────

static string PromptUser(string message)
{
    Console.Write($"{message} ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("No topic provided.")
        : input;
}

